import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check local storage for existing session
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
        setLoading(false);
    }, []);

    const login = (userData) => {
        setUser(userData);
        localStorage.setItem('user', JSON.stringify(userData));
    };

    const logout = () => {
        setUser(null);
        localStorage.removeItem('user');
    };

    if (loading) return null; // Or a loading spinner

    return (
        <AuthContext.Provider value={{ user, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import { Outlet, NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
    LayoutDashboard,
    Utensils,
    CalendarCheck,
    CreditCard,
    MessageSquare,
    LogOut,
    Menu as MenuIcon,
    X,
    Bell,
    User as UserIcon,
    ShieldAlert
} from 'lucide-react';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const DashboardLayout = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();
    const location = useLocation();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isDarkMode, setIsDarkMode] = useState(false);

    useEffect(() => {
        if (isDarkMode) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }, [isDarkMode]);

    const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

    // Define navigation links
    // All roles have access to these pages, but the page content handles role-specific features.
    const navLinks = [
        { name: 'Dashboard', path: '/dashboard', icon: <LayoutDashboard size={20} />, end: true },
        { name: 'Menu', path: '/dashboard/menu', icon: <Utensils size={20} /> },
        { name: 'Attendance', path: '/dashboard/attendance', icon: <CalendarCheck size={20} /> },
        { name: 'Payments', path: '/dashboard/payments', icon: <CreditCard size={20} /> },
        { name: 'Feedback', path: '/dashboard/feedback', icon: <MessageSquare size={20} /> },
    ];

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const closeMobileMenu = () => {
        setIsMobileMenuOpen(false);
    };

    const SidebarContent = () => (
        <div className="flex flex-col h-full bg-white border-r border-gray-100 shadow-sm relative z-20">
            {/* Brand */}
            <div className="h-16 flex items-center px-6 border-b border-gray-100">
                <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-orange-400 to-amber-500 flex items-center justify-center text-white font-bold text-lg shadow-md shadow-orange-500/20">
                        M
                    </div>
                    <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-gray-800 to-gray-600">
                        MessManager
                    </span>
                </div>
            </div>

            {/* Nav Links */}
            <div className="flex-1 px-4 py-6 space-y-1.5 overflow-y-auto">
                <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-4 px-2">
                    Main Menu
                </div>
                {navLinks.map((link) => (
                    <NavLink
                        key={link.path}
                        to={link.path}
                        end={link.end}
                        onClick={closeMobileMenu}
                        className={({ isActive }) =>
                            `flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 group relative overflow-hidden ${isActive
                                ? 'text-orange-600 bg-orange-50'
                                : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
                            }`
                        }
                    >
                        {({ isActive }) => (
                            <>
                                <div className={`${isActive ? 'text-orange-500' : 'text-gray-400 group-hover:text-gray-500'} transition-colors`}>
                                    {link.icon}
                                </div>
                                <span>{link.name}</span>
                                {isActive && (
                                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-orange-500 rounded-r-full" />
                                )}
                            </>
                        )}
                    </NavLink>
                ))}
            </div>

            {/* User Info & Logout */}
            <div className="p-4 border-t border-gray-100">
                <div className="flex items-center gap-3 px-3 py-2">
                    <div className="w-10 h-10 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center border-2 border-white shadow-sm font-bold">
                        {user?.fullName?.charAt(0) || 'U'}
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-gray-900 truncate">{user?.fullName}</p>
                        <div className="flex items-center gap-1">
                            {user?.role === 'Admin' ? (
                                <ShieldAlert size={12} className="text-orange-500" />
                            ) : (
                                <UserIcon size={12} className="text-gray-400" />
                            )}
                            <p className="text-xs text-gray-500 truncate">{user?.role}</p>
                        </div>
                    </div>
                </div>
                <button
                    onClick={handleLogout}
                    className="w-full mt-2 flex items-center justify-center gap-2 px-3 py-2 text-sm font-medium text-red-600 hover:text-red-700 hover:bg-red-50 rounded-xl transition-colors"
                >
                    <LogOut size={16} />
                    Sign Out
                </button>
            </div>
        </div>
    );

    return (
        <div className="flex h-screen bg-gray-50 font-sans overflow-hidden">
            {/* Toast Notification Container */}
            <ToastContainer
                position="top-right"
                autoClose={3000}
                hideProgressBar={false}
                newestOnTop
                closeOnClick
                rtl={false}
                pauseOnFocusLoss
                draggable
                pauseOnHover
                theme="light"
                toastClassName="rounded-xl shadow-lg border border-gray-100"
            />

            {/* Mobile Sidebar Overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm z-30 lg:hidden transition-opacity"
                    onClick={closeMobileMenu}
                />
            )}

            {/* Sidebar Navigation */}
            <aside
                className={`fixed inset-y-0 left-0 z-40 w-64 transform transition-transform duration-300 ease-in-out lg:translate-x-0 lg:static ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
                    }`}
            >
                <SidebarContent />
            </aside>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
                {/* Top Navbar */}
                <header className="h-16 bg-white/80 backdrop-blur-md border-b border-gray-100 flex items-center justify-between px-4 sm:px-6 lg:px-8 z-10 sticky top-0">

                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => setIsMobileMenuOpen(true)}
                            className="lg:hidden p-2 -ml-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                        >
                            <MenuIcon size={24} />
                        </button>
                        <h1 className="text-xl font-bold text-gray-800 hidden sm:block">
                            {navLinks.find(link => location.pathname === link.path || (link.end && location.pathname === '/dashboard'))?.name || 'Dashboard'}
                        </h1>
                    </div>

                    <div className="flex items-center gap-4">
                        {/* Dark Mode Toggle */}
                        <button
                            onClick={toggleDarkMode}
                            className="p-2 text-gray-400 hover:text-orange-500 transition-colors bg-gray-50 rounded-full border border-gray-100 dark:bg-gray-800 dark:border-gray-700"
                        >
                            {isDarkMode ? "ΓÿÇ∩╕Å" : "≡ƒîÖ"}
                        </button>
                        {/* Notification Bell stub */}
                        <button className="relative p-2 text-gray-400 hover:text-gray-500 transition-colors">
                            <Bell size={20} />
                            <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
                        </button>
                    </div>
                </header>

                {/* Dynamic Page Content */}
                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-gray-50 p-4 sm:p-6 lg:p-8">
                    <Outlet />
                </main>
            </div>
        </div>
    );
};

export default DashboardLayout;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import axiosClient from '../../api/axiosClient';
import { Card, Button, Spinner } from '../../components/ui/BaseComponents';
import { Search, CheckCircle2, XCircle } from 'lucide-react';
import { toast } from 'react-toastify';
import { format } from 'date-fns';

const Attendance = () => {
    const { user } = useAuth();
    const isAdminOrStaff = user?.role === 'Admin' || user?.role === 'Staff';

    const [attendances, setAttendances] = useState([]);
    const [loading, setLoading] = useState(true);

    // Admin/Staff specific
    const [targetDate, setTargetDate] = useState(format(new Date(), 'yyyy-MM-dd'));
    const [markData, setMarkData] = useState({ userId: '', mealType: 'Lunch', status: 'Present' });

    const fetchAttendance = async () => {
        try {
            setLoading(true);
            if (isAdminOrStaff) {
                const res = await axiosClient.get(`/attendance/date/${targetDate}`);
                setAttendances(res.data);
            } else {
                const res = await axiosClient.get(`/attendance/my`);
                setAttendances(res.data);
            }
        } catch (error) {
            toast.error('Failed to load attendance records.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchAttendance();
    }, [targetDate, isAdminOrStaff]);

    const handleMarkAttendance = async (e) => {
        e.preventDefault();
        if (!markData.userId) return toast.warning("User ID is required!");

        try {
            await axiosClient.post('/attendance', {
                formatDate: targetDate, // Just send date format normally
                date: targetDate,
                userId: parseInt(markData.userId),
                mealType: markData.mealType,
                status: markData.status
            });
            toast.success("Attendance logged successfully!");
            setMarkData({ ...markData, userId: '' }); // Reset
            fetchAttendance(); // Refresh list
        } catch (error) {
            toast.error('Failed to mark. Does the User ID exist?');
        }
    };

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-12">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Attendance Log</h1>
                    <p className="text-gray-500 text-sm mt-1">
                        {isAdminOrStaff ? "Track and mark daily attendance." : "View your personal attendance history."}
                    </p>
                </div>
            </div>

            {isAdminOrStaff && (
                <Card className="p-6 bg-gradient-to-br from-white to-blue-50/50">
                    <h3 className="text-lg font-bold text-gray-900 border-b border-gray-100 pb-4 mb-4">Mark Student Attendance</h3>

                    <form onSubmit={handleMarkAttendance} className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-5 gap-4 items-end">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">User ID</label>
                            <input
                                type="number"
                                value={markData.userId}
                                onChange={(e) => setMarkData({ ...markData, userId: e.target.value })}
                                className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                placeholder="e.g. 2"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                            <input
                                type="date"
                                value={targetDate}
                                onChange={(e) => setTargetDate(e.target.value)}
                                className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Meal</label>
                            <select
                                value={markData.mealType}
                                onChange={(e) => setMarkData({ ...markData, mealType: e.target.value })}
                                className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            >
                                <option value="Breakfast">Breakfast</option>
                                <option value="Lunch">Lunch</option>
                                <option value="Dinner">Dinner</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                            <select
                                value={markData.status}
                                onChange={(e) => setMarkData({ ...markData, status: e.target.value })}
                                className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            >
                                <option value="Present">Present (Ate)</option>
                                <option value="Absent">Absent (Missed)</option>
                            </select>
                        </div>
                        <div>
                            <Button type="submit" className="w-full bg-blue-600 hover:bg-blue-700">Submit</Button>
                        </div>
                    </form>
                </Card>
            )}

            <Card className="overflow-hidden">
                {loading ? (
                    <div className="h-64 flex items-center justify-center"><Spinner /></div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-gray-50 border-b border-gray-100 text-gray-500 text-sm uppercase tracking-wider">
                                    <th className="p-4 font-semibold">Date</th>
                                    <th className="p-4 font-semibold">Meal Type</th>
                                    {isAdminOrStaff && <th className="p-4 font-semibold">Student Name</th>}
                                    {isAdminOrStaff && <th className="p-4 font-semibold">User ID</th>}
                                    <th className="p-4 font-semibold">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 text-sm text-gray-700">
                                {attendances.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="p-8 text-center text-gray-500">No attendance records found for this view.</td>
                                    </tr>
                                ) : (
                                    attendances.map((record) => (
                                        <tr key={record.id} className="hover:bg-gray-50/50 transition-colors">
                                            <td className="p-4 font-medium">{format(new Date(record.date), 'MMM dd, yyyy')}</td>
                                            <td className="p-4">{record.mealType}</td>
                                            {isAdminOrStaff && <td className="p-4 font-medium text-gray-900">{record.userName || `User ${record.userId}`}</td>}
                                            {isAdminOrStaff && <td className="p-4 text-gray-500">#{record.userId}</td>}
                                            <td className="p-4">
                                                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold ${record.status === 'Present'
                                                        ? 'bg-green-100 text-green-700'
                                                        : 'bg-red-100 text-red-700'
                                                    }`}>
                                                    {record.status === 'Present' ? <CheckCircle2 size={14} /> : <XCircle size={14} />}
                                                    {record.status}
                                                </span>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                )}
            </Card>
        </div>
    );
};

export default Attendance;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import axiosClient from '../../api/axiosClient';
import { Card, Button, Spinner } from '../../components/ui/BaseComponents';
import { MessageSquare, Send, CheckCircle2, AlertCircle } from 'lucide-react';
import { toast } from 'react-toastify';
import { format } from 'date-fns';

const Feedback = () => {
    const { user } = useAuth();
    const isAdmin = user?.role === 'Admin';

    const [feedbackList, setFeedbackList] = useState([]);
    const [loading, setLoading] = useState(true);

    // Submit Form State
    const [formData, setFormData] = useState({ category: 'Quality', message: '' });
    const [submitting, setSubmitting] = useState(false);

    const fetchFeedback = async () => {
        try {
            setLoading(true);
            const endpoint = isAdmin ? '/feedback' : '/feedback/my';
            const res = await axiosClient.get(endpoint);
            setFeedbackList(res.data);
        } catch (error) {
            toast.error('Failed to load feedback records.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchFeedback();
    }, [isAdmin]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.message.trim()) return toast.warning("Message cannot be empty.");

        try {
            setSubmitting(true);
            await axiosClient.post('/feedback', formData);
            toast.success("Feedback submitted successfully. Thank you!");
            setFormData({ ...formData, message: '' });
            fetchFeedback();
        } catch (error) {
            toast.error('Failed to submit feedback.');
        } finally {
            setSubmitting(false);
        }
    };

    const handleMarkReviewed = async (id) => {
        try {
            await axiosClient.put(`/feedback/${id}/review`);
            toast.success("Feedback marked as reviewed.");
            fetchFeedback();
        } catch (error) {
            toast.error('Failed to update status.');
        }
    };

    const categoryColors = {
        'Quality': 'bg-blue-100 text-blue-700',
        'Hygiene': 'bg-teal-100 text-teal-700',
        'Menu': 'bg-orange-100 text-orange-700',
        'Staff': 'bg-purple-100 text-purple-700',
        'Other': 'bg-gray-100 text-gray-700',
    };

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-12 items-start flex flex-col lg:flex-row gap-8">

            {/* Left Column: Submit New Feedback (Non-Admin mostly, but anyone can technically) */}
            <div className="w-full lg:w-1/3 flex-shrink-0 space-y-6">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Feedback</h1>
                    <p className="text-gray-500 text-sm mt-1">Help us improve the mess experience.</p>
                </div>

                {!isAdmin && (
                    <Card className="p-6 bg-white border-purple-100 shadow-sm border-t-4 border-t-purple-500">
                        <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                            <MessageSquare size={20} className="text-purple-500" />
                            Write to us
                        </h3>

                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                                <select
                                    value={formData.category}
                                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-purple-500 focus:outline-none bg-gray-50"
                                >
                                    <option value="Quality">Food Quality</option>
                                    <option value="Hygiene">Hygiene & Cleanliness</option>
                                    <option value="Menu">Menu Suggestions</option>
                                    <option value="Staff">Staff Behavior</option>
                                    <option value="Other">Other</option>
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Your Message</label>
                                <textarea
                                    required
                                    rows={4}
                                    value={formData.message}
                                    onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                                    className="w-full p-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-purple-500 focus:outline-none resize-none bg-gray-50 text-sm"
                                    placeholder="Tell us what's on your mind..."
                                />
                            </div>

                            <Button
                                type="submit"
                                disabled={submitting}
                                className="w-full bg-purple-600 hover:bg-purple-700 focus:ring-purple-500"
                            >
                                {submitting ? <Spinner size={18} className="text-white mx-auto" /> : (
                                    <>
                                        <Send size={18} className="mr-2" />
                                        Submit Feedback
                                    </>
                                )}
                            </Button>
                        </form>
                    </Card>
                )}
            </div>

            {/* Right Column: Feedback Feed */}
            <div className="w-full lg:flex-1 space-y-4 pt-1 lg:pt-14">
                <div className="flex justify-between items-center mb-2">
                    <h3 className="text-lg font-bold text-gray-900">
                        {isAdmin ? "All Received Feedback" : "Your Previous Feedback"}
                    </h3>
                    <span className="bg-gray-100 text-gray-600 px-3 py-1 rounded-full text-xs font-bold">
                        {feedbackList.length} total
                    </span>
                </div>

                {loading ? (
                    <div className="py-12 flex justify-center"><Spinner /></div>
                ) : feedbackList.length === 0 ? (
                    <div className="text-center py-16 bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                        <MessageSquare size={40} className="mx-auto text-gray-300 mb-3" />
                        <h3 className="text-lg font-medium text-gray-900">It's quiet here</h3>
                        <p className="text-gray-500 mt-1">No feedback has been submitted yet.</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {feedbackList.map((feedback) => (
                            <Card key={feedback.id} className={`p-5 flex flex-col gap-3 ${feedback.status === 'Pending' ? 'bg-white' : 'bg-gray-50/50 opacity-80'}`}>
                                <div className="flex justify-between items-start">
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2.5 py-1 rounded-full text-xs font-semibold ${categoryColors[feedback.category] || categoryColors['Other']}`}>
                                            {feedback.category}
                                        </span>
                                        <span className="text-xs font-medium text-gray-400 flex items-center gap-1">
                                            <Clock size={12} />
                                            {format(new Date(feedback.createdAt), 'MMM dd, h:mm a')}
                                        </span>
                                    </div>

                                    <span className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-md ${feedback.status === 'Reviewed' ? 'text-green-600 bg-green-50' : 'text-amber-500 bg-amber-50'
                                        }`}>
                                        {feedback.status === 'Reviewed' ? <CheckCircle2 size={12} /> : <AlertCircle size={12} />}
                                        {feedback.status}
                                    </span>
                                </div>

                                <p className="text-gray-700 text-sm leading-relaxed mt-1">{feedback.message}</p>

                                {isAdmin && (
                                    <div className="pt-3 border-t border-gray-100 mt-2 flex justify-between items-center">
                                        <div className="text-xs font-medium text-gray-500">
                                            From: <span className="font-bold text-gray-800">{feedback.userName}</span> ({feedback.userRole})
                                        </div>
                                        {feedback.status === 'Pending' && (
                                            <Button
                                                onClick={() => handleMarkReviewed(feedback.id)}
                                                size="sm"
                                                variant="secondary"
                                                className="py-1 bg-white border border-gray-200 shadow-sm text-xs text-gray-700 hover:text-green-600 hover:border-green-200"
                                            >
                                                <CheckCircle2 size={14} className="mr-1.5" />
                                                Mark Reviewed
                                            </Button>
                                        )}
                                    </div>
                                )}
                            </Card>
                        ))}
                    </div>
                )}
            </div>

        </div>
    );
};

export default Feedback;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import axiosClient from '../../api/axiosClient';
import { Card, Button, Spinner } from '../../components/ui/BaseComponents';
import { Search, Plus, Edit2, Trash2, CalendarDays } from 'lucide-react';
import { toast } from 'react-toastify';

const Menu = () => {
    const { user } = useAuth();
    const isAdmin = user?.role === 'Admin';

    const [menus, setMenus] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');

    // Form State
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingId, setEditingId] = useState(null);
    const [formData, setFormData] = useState({
        dayOfWeek: 'Monday',
        breakfast: '',
        lunch: '',
        dinner: ''
    });

    const fetchMenu = async () => {
        try {
            setLoading(true);
            const res = await axiosClient.get('/menu');
            setMenus(res.data);
        } catch (error) {
            toast.error('Failed to load menu data.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchMenu();
    }, []);

    const handleOpenForm = (menu = null) => {
        if (menu) {
            setEditingId(menu.id);
            setFormData({
                dayOfWeek: menu.dayOfWeek,
                breakfast: menu.breakfast,
                lunch: menu.lunch,
                dinner: menu.dinner
            });
        } else {
            setEditingId(null);
            setFormData({ dayOfWeek: 'Monday', breakfast: '', lunch: '', dinner: '' });
        }
        setIsFormOpen(true);
    };

    const handleCloseForm = () => {
        setIsFormOpen(false);
        setEditingId(null);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingId) {
                await axiosClient.put(`/menu/${editingId}`, formData);
                toast.success(`Updated menu for ${formData.dayOfWeek}`);
            } else {
                await axiosClient.post('/menu', formData);
                toast.success(`Added new menu for ${formData.dayOfWeek}`);
            }
            handleCloseForm();
            fetchMenu();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to save menu.');
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm("Are you sure you want to delete this specific menu plan?")) return;
        try {
            await axiosClient.delete(`/menu/${id}`);
            toast.success("Menu item deleted.");
            fetchMenu();
        } catch (error) {
            toast.error('Failed to delete menu.');
        }
    };

    const filteredMenus = menus.filter(m =>
        m.dayOfWeek.toLowerCase().includes(search.toLowerCase()) ||
        m.lunch.toLowerCase().includes(search.toLowerCase())
    );

    const daysOfWeek = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

    if (loading && !menus.length) {
        return <div className="h-full flex items-center justify-center"><Spinner size={40} /></div>;
    }

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-12">
            {/* Header & Controls */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Weekly Menu</h1>
                    <p className="text-gray-500 text-sm mt-1">Review the meal plan and daily offerings.</p>
                </div>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search by day or dish..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"
                        />
                    </div>
                    {isAdmin && (
                        <Button onClick={() => handleOpenForm()} className="whitespace-nowrap">
                            <Plus size={18} className="mr-2" />
                            Add Menu
                        </Button>
                    )}
                </div>
            </div>

            {/* Grid List */}
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                {filteredMenus.map((menu) => (
                    <Card key={menu.id} className="hover:border-orange-200 transition-colors flex flex-col">
                        <div className="p-5 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
                            <div className="flex items-center gap-2">
                                <CalendarDays size={20} className="text-orange-500" />
                                <h3 className="font-bold text-gray-900 text-lg">{menu.dayOfWeek}</h3>
                            </div>

                            {/* Admin Actions */}
                            {isAdmin && (
                                <div className="flex gap-1.5 pt-0.5">
                                    <button
                                        onClick={() => handleOpenForm(menu)}
                                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                    >
                                        <Edit2 size={16} />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(menu.id)}
                                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            )}
                        </div>

                        <div className="p-5 space-y-4 flex-1">
                            <div>
                                <p className="text-xs uppercase tracking-wider font-semibold text-gray-400 mb-1">Breakfast (8:00 AM)</p>
                                <p className="text-gray-800 font-medium">{menu.breakfast}</p>
                            </div>
                            <div className="pt-2 border-t border-gray-50">
                                <p className="text-xs uppercase tracking-wider font-semibold text-gray-400 mb-1">Lunch (1:00 PM)</p>
                                <p className="text-gray-800 font-medium">{menu.lunch}</p>
                            </div>
                            <div className="pt-2 border-t border-gray-50">
                                <p className="text-xs uppercase tracking-wider font-semibold text-gray-400 mb-1">Dinner (8:00 PM)</p>
                                <p className="text-gray-800 font-medium">{menu.dinner}</p>
                            </div>
                        </div>
                    </Card>
                ))}
            </div>

            {filteredMenus.length === 0 && !loading && (
                <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-gray-300">
                    <Utensils size={40} className="mx-auto text-gray-300 mb-3" />
                    <h3 className="text-lg font-medium text-gray-900">No menu items found</h3>
                    <p className="text-gray-500 mt-1">Try adjusting your search query.</p>
                </div>
            )}

            {/* Admin Add/Edit Modal */}
            {isFormOpen && isAdmin && (
                <div className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <Card className="w-full max-w-md bg-white shadow-2xl animate-fade-in">
                        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                            <h2 className="text-xl font-bold text-gray-900">
                                {editingId ? 'Edit Daily Menu' : 'Add Daily Menu'}
                            </h2>
                            <button onClick={handleCloseForm} className="text-gray-400 hover:text-gray-600">
                                &times;
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Day of Week</label>
                                <select
                                    value={formData.dayOfWeek}
                                    onChange={(e) => setFormData({ ...formData, dayOfWeek: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none"
                                    required
                                >
                                    {daysOfWeek.map(day => (
                                        <option key={day} value={day}>{day}</option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Breakfast Menu</label>
                                <textarea
                                    value={formData.breakfast}
                                    onChange={(e) => setFormData({ ...formData, breakfast: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none resize-none"
                                    rows={2}
                                    required
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Lunch Menu</label>
                                <textarea
                                    value={formData.lunch}
                                    onChange={(e) => setFormData({ ...formData, lunch: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none resize-none"
                                    rows={2}
                                    required
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Dinner Menu</label>
                                <textarea
                                    value={formData.dinner}
                                    onChange={(e) => setFormData({ ...formData, dinner: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:outline-none resize-none"
                                    rows={2}
                                    required
                                />
                            </div>

                            <div className="pt-4 flex gap-3 justify-end">
                                <Button type="button" variant="secondary" onClick={handleCloseForm}>Cancel</Button>
                                <Button type="submit">Save Menu</Button>
                            </div>
                        </form>
                    </Card>
                </div>
            )}
        </div>
    );
};

export default Menu;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import axiosClient from '../../api/axiosClient';
import { Card, Button, Spinner } from '../../components/ui/BaseComponents';
import { Search, DollarSign, ReceiptText, CheckCircle2, Clock } from 'lucide-react';
import { toast } from 'react-toastify';
import { format } from 'date-fns';

const Payments = () => {
    const { user } = useAuth();
    const isAdmin = user?.role === 'Admin';

    const [payments, setPayments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');

    // Admin form
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [invoiceData, setInvoiceData] = useState({ userId: '', amount: 1500, invoiceMonth: format(new Date(), 'MMMM yyyy') });

    const fetchPayments = async () => {
        try {
            setLoading(true);
            const endpoint = isAdmin ? '/payment' : '/payment/my';
            const res = await axiosClient.get(endpoint);
            setPayments(res.data);
        } catch (error) {
            toast.error('Failed to load payments.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPayments();
    }, [isAdmin]);

    const handleCreateInvoice = async (e) => {
        e.preventDefault();
        try {
            await axiosClient.post('/payment', {
                userId: parseInt(invoiceData.userId),
                amount: parseFloat(invoiceData.amount),
                invoiceMonth: invoiceData.invoiceMonth,
                status: 'Pending'
            });
            toast.success('Invoice created successfully.');
            setIsFormOpen(false);
            setInvoiceData({ ...invoiceData, userId: '' });
            fetchPayments();
        } catch (error) {
            toast.error('Failed to create invoice.');
        }
    };

    const handlePay = async (id) => {
        if (!window.confirm("Confirm payment processing?")) return;
        try {
            await axiosClient.put(`/payment/${id}/pay`);
            toast.success("Payment marked as paid!");
            fetchPayments();
        } catch (error) {
            toast.error('Payment processing failed.');
        }
    };

    const filteredPayments = payments.filter(p =>
        p.invoiceMonth.toLowerCase().includes(search.toLowerCase()) ||
        (p.userName && p.userName.toLowerCase().includes(search.toLowerCase()))
    );

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-12">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Payments & Dues</h1>
                    <p className="text-gray-500 text-sm mt-1">
                        {isAdmin ? "Manage student invoices and track revenue." : "View your billing history and settle outstanding dues."}
                    </p>
                </div>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder={isAdmin ? "Search by student or month..." : "Search by month..."}
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                    </div>
                    {isAdmin && (
                        <Button onClick={() => setIsFormOpen(true)} className="bg-emerald-600 hover:bg-emerald-700 focus:ring-emerald-500 whitespace-nowrap">
                            <ReceiptText size={18} className="mr-2" />
                            New Invoice
                        </Button>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                {/* Left Side: Summary or Admin Tools */}
                <div className="lg:col-span-1 space-y-6">
                    <Card className="p-6 bg-gradient-to-br from-emerald-500 to-teal-600 text-white border-0">
                        <div className="flex items-center gap-3 mb-4 text-emerald-100">
                            <DollarSign size={24} />
                            <h3 className="font-semibold uppercase tracking-wider text-sm">Overview</h3>
                        </div>
                        {isAdmin ? (
                            <div>
                                <p className="text-emerald-100 text-sm mb-1">Total Unpaid Invoices</p>
                                <h2 className="text-4xl font-bold mb-4">{payments.filter(p => p.status === 'Pending').length}</h2>
                            </div>
                        ) : (
                            <div>
                                <p className="text-emerald-100 text-sm mb-1">My Outstanding Balance</p>
                                <h2 className="text-4xl font-bold mb-4">
                                    ${payments.filter(p => p.status === 'Pending').reduce((acc, p) => acc + p.amount, 0)}
                                </h2>
                            </div>
                        )}
                        <div className="pt-4 border-t border-emerald-400/30">
                            <p className="text-sm font-medium">Keep your account in good standing.</p>
                        </div>
                    </Card>
                </div>

                {/* Right Side: Data Table */}
                <Card className="lg:col-span-3 overflow-hidden flex flex-col min-h-[400px]">
                    {loading ? (
                        <div className="flex-1 flex items-center justify-center"><Spinner /></div>
                    ) : (
                        <div className="overflow-x-auto flex-1">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-gray-50 border-b border-gray-100 text-gray-500 text-sm uppercase tracking-wider">
                                        <th className="p-4 font-semibold">Invoice Month</th>
                                        {isAdmin && <th className="p-4 font-semibold">Student Name</th>}
                                        <th className="p-4 font-semibold">Amount</th>
                                        <th className="p-4 font-semibold">Status</th>
                                        <th className="p-4 font-semibold text-right">Action</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100 text-sm text-gray-700">
                                    {filteredPayments.length === 0 ? (
                                        <tr>
                                            <td colSpan={5} className="p-12 text-center">
                                                <ReceiptText size={48} className="mx-auto text-gray-300 mb-3" />
                                                <p className="text-gray-500 font-medium text-lg">No payment records found.</p>
                                            </td>
                                        </tr>
                                    ) : (
                                        filteredPayments.map((payment) => (
                                            <tr key={payment.id} className="hover:bg-gray-50/50 transition-colors">
                                                <td className="p-4 font-medium text-gray-900">{payment.invoiceMonth}</td>
                                                {isAdmin && <td className="p-4">{payment.userName}</td>}
                                                <td className="p-4 font-bold text-gray-900">${payment.amount}</td>
                                                <td className="p-4">
                                                    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold ${payment.status === 'Paid'
                                                            ? 'bg-emerald-100 text-emerald-700'
                                                            : 'bg-amber-100 text-amber-700'
                                                        }`}>
                                                        {payment.status === 'Paid' ? <CheckCircle2 size={14} /> : <Clock size={14} />}
                                                        {payment.status}
                                                    </span>
                                                </td>
                                                <td className="p-4 text-right">
                                                    {payment.status === 'Pending' ? (
                                                        <Button
                                                            onClick={() => handlePay(payment.id)}
                                                            size="sm"
                                                            className="py-1.5 px-3 bg-emerald-100 text-emerald-700 hover:bg-emerald-200 border-0"
                                                        >
                                                            Pay Now
                                                        </Button>
                                                    ) : (
                                                        <span className="text-xs font-medium text-gray-400 block px-3 py-1.5">
                                                            Settled {payment.datePaid && format(new Date(payment.datePaid), 'MMM dd')}
                                                        </span>
                                                    )}
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </Card>
            </div>

            {isFormOpen && isAdmin && (
                <div className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <Card className="w-full max-w-sm bg-white shadow-2xl animate-fade-in">
                        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                            <h2 className="text-xl font-bold text-gray-900">Issue Invoice</h2>
                            <button onClick={() => setIsFormOpen(false)} className="text-gray-400 hover:text-gray-600">&times;</button>
                        </div>
                        <form onSubmit={handleCreateInvoice} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">User ID</label>
                                <input
                                    type="number"
                                    required
                                    value={invoiceData.userId}
                                    onChange={(e) => setInvoiceData({ ...invoiceData, userId: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500"
                                    placeholder="e.g. 2"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Amount ($)</label>
                                <input
                                    type="number"
                                    required
                                    value={invoiceData.amount}
                                    onChange={(e) => setInvoiceData({ ...invoiceData, amount: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Billing Month</label>
                                <input
                                    type="text"
                                    required
                                    value={invoiceData.invoiceMonth}
                                    onChange={(e) => setInvoiceData({ ...invoiceData, invoiceMonth: e.target.value })}
                                    className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500"
                                />
                            </div>
                            <div className="pt-4">
                                <Button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700">Send Invoice</Button>
                            </div>
                        </form>
                    </Card>
                </div>
            )}
        </div>
    );
};

export default Payments;
